const DAYS = [
  { k: 0, en: "Sunday", short: "Sun" },
  { k: 1, en: "Monday", short: "Mon" },
  { k: 2, en: "Tuesday", short: "Tue" },
  { k: 3, en: "Wednesday", short: "Wed" },
  { k: 4, en: "Thursday", short: "Thu" },
];
function ttKey(dept, year) { return (dept || "") + "__" + (year || ""); }
function parseTTKey(key) { const i = key.indexOf("__"); return [key.slice(0, i), key.slice(i + 2)]; }
function deptColor(d) { return (DEPT_THEME[d] || {}).color || "#8B5CF6"; }
function dayLabel(k) { const d = DAYS.find((x) => x.k === k); return d ? t("dn" + k) : ""; }
function classEntries(tt, dept, year) { return ((tt || {})[ttKey(dept, year)] || []).slice(); }
function sortByStart(arr) { return arr.slice().sort((a, b) => (a.start || "").localeCompare(b.start || "")); }
function teacherDayEntries(tt, teacherId, dayK) {
  const out = [];
  Object.keys(tt || {}).forEach((key) => {
    const [dept, year] = parseTTKey(key);
    (tt[key] || []).forEach((e) => { if (e.day === dayK && e.teacherId === teacherId) out.push({ ...e, dept, year }); });
  });
  return sortByStart(out);
}

