let CURRENT_LANG = "en";
function t(key) { const L = I18N[CURRENT_LANG] || I18N.en; return (key in L ? L[key] : I18N.en[key]) || key; }
function roleLabel(r) { return t("role_" + r); }
function yearLabel(y) { return t("yr") + " " + y; }

