const ACADEMIC_YEAR = "2025 / 2026";
function hashStr(s) { let h = 2166136261 >>> 0; for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = Math.imul(h, 16777619) >>> 0; } return h >>> 0; }
function visibleAnns(anns, user) {
  return (anns || []).filter((a) => {
    if (a.audience === "all") return true;
    if (a.audience === "students") return user.role === "student";
    if (a.audience === "teachers") return user.role === "teacher";
    if (a.audience && a.audience.indexOf("dept:") === 0) return user.department === a.audience.slice(5);
    return false;
  }).slice().sort((a, b) => b.createdAt - a.createdAt);
}
function audLabel(aud) {
  if (aud === "all") return "Everyone";
  if (aud === "students") return "All students";
  if (aud === "teachers") return "All teachers";
  if (aud && aud.indexOf("dept:") === 0) return aud.slice(5);
  return aud;
}
function timeAgo(ts) {
  const s = Math.floor((Date.now() - ts) / 1000);
  if (s < 60) return "just now";
  const m = Math.floor(s / 60); if (m < 60) return m + " min ago";
  const h = Math.floor(m / 60); if (h < 24) return h + " h ago";
  const d = Math.floor(h / 24); if (d < 7) return d + " d ago";
  return new Date(ts).toLocaleDateString();
}
function dueStatus(due) {
  if (!due) return { label: t("due_none"), cls: "due-far" };
  const d = new Date(due + "T00:00:00");
  const now = new Date();
  const t0 = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const diff = Math.round((d - t0) / 86400000);
  if (isNaN(diff)) return { label: t("due_none"), cls: "due-far" };
  if (diff < 0) return { label: t("due_over"), cls: "due-over" };
  if (diff === 0) return { label: t("due_today"), cls: "due-today" };
  if (diff <= 3) return { label: t("due_in") + " " + diff + " " + (diff === 1 ? t("due_day") : t("due_days")), cls: "due-soon" };
  return { label: t("due_on") + " " + d.toLocaleDateString(), cls: "due-far" };
}

