/* ---- storage: persists across sessions, falls back to memory ---- */
const mem = {};
async function dbGet(key) {
  try {
    if (typeof window !== "undefined" && window.storage && window.storage.get) {
      const r = await window.storage.get(key, true);
      return r ? r.value : null;
    }
  } catch (e) {}
  return key in mem ? mem[key] : null;
}
async function dbSet(key, value) {
  try {
    if (typeof window !== "undefined" && window.storage && window.storage.set) {
      await window.storage.set(key, value, true);
      return true;
    }
  } catch (e) {}
  mem[key] = value;
  return true;
}

/* ---- helpers ---- */
function nextId(users, role) {
  const prefix = ROLE_META[role].prefix;
  const n = users.filter((u) => u.role === role).length + 1;
  return prefix + String(n).padStart(3, "0");
}
function initials(name) {
  return (name || "").trim().split(/\s+/).map((p) => p[0] || "").slice(0, 2).join("").toUpperCase();
}
function hashPw(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return "h" + h.toString(16);
}
function resizeImage(file, max = 256, quality = 0.72) {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const dataUrl = e.target.result;
      const img = new Image();
      img.onload = () => {
        try {
          let w = img.width, h = img.height;
          if (w > h && w > max) { h = Math.round((h * max) / w); w = max; }
          else if (h > max) { w = Math.round((w * max) / h); h = max; }
          const c = document.createElement("canvas");
          c.width = w; c.height = h;
          c.getContext("2d").drawImage(img, 0, 0, w, h);
          resolve(c.toDataURL("image/jpeg", quality));
        } catch (_) { resolve(dataUrl); }
      };
      img.onerror = () => resolve(dataUrl);
      img.src = dataUrl;
    };
    reader.onerror = () => resolve(null);
    reader.readAsDataURL(file);
  });
}
