function FakeQR({ value, size = 66, fg = "#0c2245" }) {
  const N = 21;
  let seed = hashStr(String(value) + "::sava");
  const rnd = () => { seed = (Math.imul(seed, 1664525) + 1013904223) >>> 0; return seed / 4294967296; };
  const finders = [[0, 0], [0, 14], [14, 0]];
  const seps = [[0, 0], [0, 13], [13, 0]];
  const inFinder = (r, c) => { for (const [br, bc] of finders) if (r >= br && r < br + 7 && c >= bc && c < bc + 7) return [br, bc]; return null; };
  const inSep = (r, c) => { for (const [br, bc] of seps) if (r >= br && r < br + 8 && c >= bc && c < bc + 8) return true; return false; };
  const cells = [];
  for (let r = 0; r < N; r++) for (let c = 0; c < N; c++) {
    const f = inFinder(r, c);
    if (f) { const lr = r - f[0], lc = c - f[1]; const ring = lr === 0 || lr === 6 || lc === 0 || lc === 6; const core = lr >= 2 && lr <= 4 && lc >= 2 && lc <= 4; if (ring || core) cells.push([r, c]); continue; }
    if (inSep(r, c)) continue;
    if (rnd() > 0.5) cells.push([r, c]);
  }
  return (
    <svg className="qr" width={size} height={size} viewBox="-2 -2 25 25" shapeRendering="crispEdges">
      <rect x="-2" y="-2" width="25" height="25" fill="#fff" />
      {cells.map(([r, c], i) => <rect key={i} x={c} y={r} width="1.03" height="1.03" fill={fg} />)}
    </svg>
  );
}

