function PhotoPicker({ value, onChange, color = "#8B5CF6" }) {
  const [busy, setBusy] = useState(false);
  async function pick(e) {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    setBusy(true);
    const result = await resizeImage(file);
    setBusy(false);
    if (result) onChange(result);
    e.target.value = "";
  }
  return (
    <div className="photo-picker">
      <div className="photo-frame" style={{ borderColor: color }}>
        {value ? <img src={value} alt="profile" /> : <span className="photo-empty">No photo</span>}
      </div>
      <div className="photo-actions">
        <label className="btn-ghost small file-btn">
          {busy ? "Loading…" : value ? "Change photo" : "Upload photo"}
          <input type="file" accept="image/*" onChange={pick} className="file-input" />
        </label>
        {value && <button className="btn-ghost small danger" onClick={() => onChange(null)}>Remove</button>}
      </div>
    </div>
  );
}

