function DeptBanner({ department, year }) {
  const t = DEPT_THEME[department];
  if (!t) return null;
  return (
    <div className="dept-banner" style={{ background: "linear-gradient(135deg, " + t.color + "30, " + t.color + "08)", borderColor: t.color + "44" }}>
      <div className="dept-scene"><DeptScene department={department} /></div>
      <div className="dept-emblem" style={{ background: t.color + "22", color: t.color, borderColor: t.color + "55" }}>
        <DeptIcon department={department} />
      </div>
      <div className="dept-text">
        <div className="dept-name">{department}</div>
        <div className="dept-tag">{t.tag}{year ? " · Year " + year : ""}</div>
      </div>
    </div>
  );
}

export default function App() {
  const [loading, setLoading] = useState(true);
  const [users, setUsers] = useState([]);
  const [academics, setAcademics] = useState({ subjects: [], grades: {} });
  const [finance, setFinance] = useState({});
  const [attendance, setAttendance] = useState({});
  const [announcements, setAnnouncements] = useState([]);
  const [reads, setReads] = useState({});
  const [timetable, setTimetable] = useState({});
  const [assignments, setAssignments] = useState([]);
  const [done, setDone] = useState({});
  const [chat, setChat] = useState({ convos: [], messages: {} });
  const [chatReads, setChatReads] = useState({});
  const [screen, setScreen] = useState("landing");
  const [currentId, setCurrentId] = useState(null);
  const [lang, setLangState] = useState("en");
  const [theme, setThemeState] = useState("dark");

  useEffect(() => {
    (async () => {
      const raw = await dbGet(STORE_KEY);
      const list = raw ? JSON.parse(raw) : [];
      setUsers(list);
      try {
        const a = await dbGet(ACAD_KEY);
        if (a) setAcademics({ subjects: [], grades: {}, ...JSON.parse(a) });
      } catch (_) {}
      try {
        const fdat = await dbGet(FIN_KEY);
        if (fdat) setFinance(JSON.parse(fdat));
      } catch (_) {}
      try {
        const adat = await dbGet(ATT_KEY);
        if (adat) setAttendance(JSON.parse(adat));
      } catch (_) {}
      try {
        const ndat = await dbGet(ANN_KEY);
        if (ndat) setAnnouncements(JSON.parse(ndat));
      } catch (_) {}
      try {
        const rdat = await dbGet(READS_KEY);
        if (rdat) setReads(JSON.parse(rdat));
      } catch (_) {}
      try {
        const ttd = await dbGet(TT_KEY);
        if (ttd) setTimetable(JSON.parse(ttd));
      } catch (_) {}
      try {
        const asg = await dbGet(ASG_KEY);
        if (asg) setAssignments(JSON.parse(asg));
      } catch (_) {}
      try {
        const dn = await dbGet(DONE_KEY);
        if (dn) setDone(JSON.parse(dn));
      } catch (_) {}
      try {
        const cdat = await dbGet(CHAT_KEY);
        if (cdat) setChat(JSON.parse(cdat));
      } catch (_) {}
      try {
        const crd = await dbGet(CHATREADS_KEY);
        if (crd) setChatReads(JSON.parse(crd));
      } catch (_) {}
      try {
        const ldat = await dbGet(LANG_KEY);
        if (ldat && I18N[ldat]) setLangState(ldat);
      } catch (_) {}
      try {
        const tdat = await dbGet(THEME_KEY);
        if (tdat) setThemeState(tdat);
      } catch (_) {}
      let resumed = false;
      try {
        const sid = await dbGet(SESSION_KEY);
        if (sid && list.find((u) => u.id === sid)) { setCurrentId(sid); setScreen("portal"); resumed = true; }
      } catch (_) {}
      if (!resumed) setScreen("landing");
      setLoading(false);
    })();
  }, []);

  async function saveUsers(list) {
    setUsers(list);
    await dbSet(STORE_KEY, JSON.stringify(list));
  }
  async function saveAcademics(a) {
    setAcademics(a);
    await dbSet(ACAD_KEY, JSON.stringify(a));
  }
  async function saveFinance(f) {
    setFinance(f);
    await dbSet(FIN_KEY, JSON.stringify(f));
  }
  async function saveAttendance(a) {
    setAttendance(a);
    await dbSet(ATT_KEY, JSON.stringify(a));
  }
  async function saveAnnouncements(a) {
    setAnnouncements(a);
    await dbSet(ANN_KEY, JSON.stringify(a));
  }
  async function saveReads(r) {
    setReads(r);
    await dbSet(READS_KEY, JSON.stringify(r));
  }
  async function saveTimetable(tt) {
    setTimetable(tt);
    await dbSet(TT_KEY, JSON.stringify(tt));
  }
  async function saveAssignments(a) {
    setAssignments(a);
    await dbSet(ASG_KEY, JSON.stringify(a));
  }
  async function saveDone(d) {
    setDone(d);
    await dbSet(DONE_KEY, JSON.stringify(d));
  }
  async function saveChat(c) {
    setChat(c);
    await dbSet(CHAT_KEY, JSON.stringify(c));
  }
  async function saveChatReads(r) {
    setChatReads(r);
    await dbSet(CHATREADS_KEY, JSON.stringify(r));
  }

  useEffect(() => {
    let alive = true;
    const iv = setInterval(async () => {
      try {
        const c = await dbGet(CHAT_KEY);
        if (alive && c) setChat((prev) => (JSON.stringify(prev) === c ? prev : JSON.parse(c)));
        const r = await dbGet(CHATREADS_KEY);
        if (alive && r) setChatReads((prev) => (JSON.stringify(prev) === r ? prev : JSON.parse(r)));
      } catch (_) {}
    }, 4000);
    return () => { alive = false; clearInterval(iv); };
  }, []);
  async function setLang(code) {
    setLangState(code);
    await dbSet(LANG_KEY, code);
  }
  async function setTheme(code) {
    setThemeState(code);
    await dbSet(THEME_KEY, code);
  }
  function login(u) { setCurrentId(u.id); setScreen("portal"); dbSet(SESSION_KEY, u.id); }
  function logout() { setCurrentId(null); setScreen("login"); dbSet(SESSION_KEY, ""); }

  if (loading) {
    return <div className="sava-root center"><Styles /><Logo size={74} /><p className="muted" style={{ marginTop: 18 }}>Loading your portal…</p></div>;
  }
  const current = users.find((u) => u.id === currentId) || null;
  const enter = () => setScreen(users.length === 0 ? "setup" : "login");
  CURRENT_LANG = lang;
  const dir = (I18N[lang] || I18N.en).dir;

  return (
    <div className={"sava-root" + (theme === "light" ? " theme-light" : "")} dir={dir}>
      <Styles />
      {screen === "landing" && <Landing onEnter={enter} lang={lang} setLang={setLang} />}
      {screen === "setup" && <AuthShell lang={lang} setLang={setLang}><Setup users={users} saveUsers={saveUsers} onDone={login} /></AuthShell>}
      {screen === "login" && <AuthShell lang={lang} setLang={setLang}><Login users={users} onLogin={login} onBack={() => setScreen("landing")} onCreateAccount={() => setScreen("signup")} /></AuthShell>}
      {screen === "signup" && <AuthShell lang={lang} setLang={setLang}><Signup users={users} saveUsers={saveUsers} onDone={login} onBack={() => setScreen("login")} /></AuthShell>}
      {screen === "portal" && current && <Portal current={current} users={users} saveUsers={saveUsers} academics={academics} saveAcademics={saveAcademics} finance={finance} saveFinance={saveFinance} attendance={attendance} saveAttendance={saveAttendance} announcements={announcements} saveAnnouncements={saveAnnouncements} reads={reads} saveReads={saveReads} timetable={timetable} saveTimetable={saveTimetable} assignments={assignments} saveAssignments={saveAssignments} done={done} saveDone={saveDone} chat={chat} saveChat={saveChat} chatReads={chatReads} saveChatReads={saveChatReads} lang={lang} setLang={setLang} theme={theme} setTheme={setTheme} onSignOut={logout} />}
    </div>
  );
}

function AuthShell({ children, lang, setLang }) {
  return (<><CinematicBg /><div className="auth-wrap">{children}<LangSwitch lang={lang} setLang={setLang} /></div></>);
}

function LangSwitch({ lang, setLang, compact }) {
  const short = { en: "EN", ku: "KU", ar: "AR" };
  return (
    <div className="lang-switch">
      {Object.keys(I18N).map((code) => (
        <button key={code} className={"lang-btn" + (lang === code ? " on" : "")} onClick={() => setLang(code)}>{compact ? short[code] : I18N[code].name}</button>
      ))}
    </div>
  );
}

function ThemeToggle({ theme, setTheme }) {
  const dark = theme !== "light";
  return <button className="theme-toggle" onClick={() => setTheme(dark ? "light" : "dark")} title="Toggle light / dark">{dark ? "☀" : "☾"}</button>;
}

function SearchBox({ value, onChange, placeholder }) {
  return (
    <div className="searchbox">
      <span className="search-ic">⌕</span>
      <input className="input" value={value} onChange={(e) => onChange(e.target.value)} placeholder={placeholder || "Search by name…"} />
      {value ? <button className="search-clear" onClick={() => onChange("")}>✕</button> : null}
    </div>
  );
}
function matchName(u, q) {
  const s = q.trim().toLowerCase();
  if (!s) return true;
  return ((u.name || "") + " " + (u.id || "")).toLowerCase().includes(s);
}

/* ================= SETUP ================= */
function Setup({ users, saveUsers, onDone }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [pw, setPw] = useState("");
  const [err, setErr] = useState("");
  async function create() {
    if (!name.trim()) return setErr("Enter your full name.");
    if (pw.length < 4) return setErr("Use a password of at least 4 characters.");
    const admin = { ...emptyPerson("admin"), id: nextId(users, "admin"), name: name.trim(), email: email.trim(), pw: hashPw(pw), createdAt: Date.now() };
    await saveUsers([...users, admin]);
    onDone(admin);
  }
  return (
    <>
      <div className="auth-head"><Logo size={68} /></div>
      <div className="card glass">
        <span className="eyebrow">{t("firstSetup")}</span>
        <h1 className="h1">{t("createAdminTitle")}</h1>
        <p className="muted">{t("setupSub")}</p>
        <Field label={t("fullName")}><input className="input" value={name} onChange={(e) => { setName(e.target.value); setErr(""); }} placeholder="e.g. Aland Karim" /></Field>
        <Field label={t("emailOpt")}><input className="input" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="you@sava.edu" /></Field>
        <Field label={t("password")}><input className="input" type="password" value={pw} onChange={(e) => { setPw(e.target.value); setErr(""); }} placeholder={t("choosePassword")} /></Field>
        {err && <div className="err">{err}</div>}
        <button className="btn-primary" onClick={create}>{t("createAdminBtn")}</button>
      </div>
    </>
  );
}

/* ================= LOGIN ================= */
function Login({ users, onLogin, onBack, onCreateAccount }) {
  const [idv, setIdv] = useState("");
  const [pw, setPw] = useState("");
  const [err, setErr] = useState("");
  function submit() {
    const key = idv.trim().toLowerCase();
    if (!key) return setErr("Enter your ID or email.");
    const u = users.find((x) => x.id.toLowerCase() === key || (x.email && x.email.toLowerCase() === key));
    if (!u) return setErr("No account matches that ID or email.");
    if (u.pw !== hashPw(pw)) return setErr("That password doesn't match.");
    onLogin(u);
  }
  return (
    <>
      <div className="auth-head"><Logo size={68} /></div>
      <div className="card glass">
        <span className="eyebrow">SAVA Portal</span>
        <h1 className="h1">{t("welcomeBack")}</h1>
        <p className="muted">{t("signinSub")}</p>
        <Field label={t("idOrEmail")}><input className="input" value={idv} onChange={(e) => { setIdv(e.target.value); setErr(""); }} placeholder="e.g. STU001 or you@sava.edu" /></Field>
        <Field label={t("password")}><input className="input" type="password" value={pw} onChange={(e) => { setPw(e.target.value); setErr(""); }} placeholder="••••••••" onKeyDown={(e) => e.key === "Enter" && submit()} /></Field>
        {err && <div className="err">{err}</div>}
        <button className="btn-primary" onClick={submit}>{t("enter")}</button>
        {onCreateAccount && <button className="link-create" onClick={onCreateAccount}>{t("su_prompt")}</button>}
        {onBack && <button className="link-back" onClick={onBack}>{t("back")}</button>}
      </div>
    </>
  );
}

/* ================= SIGN UP ================= */
function Signup({ users, saveUsers, onDone, onBack }) {
  const [role, setRole] = useState("student");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [pw, setPw] = useState("");
  const [dept, setDept] = useState(DEPARTMENTS[0]);
  const [year, setYear] = useState("1");
  const [err, setErr] = useState("");

  async function create() {
    if (!name.trim()) return setErr(t("su_err_name"));
    if (pw.length < 4) return setErr(t("su_err_pw"));
    if (email.trim()) {
      const ek = email.trim().toLowerCase();
      if (users.some((u) => u.email && u.email.toLowerCase() === ek)) return setErr(t("su_err_email"));
    }
    const u = {
      ...emptyPerson(role), id: nextId(users, role), name: name.trim(), email: email.trim(),
      pw: hashPw(pw), department: dept, year: role === "student" ? year : "",
      self: true, isNew: true, createdAt: Date.now(),
    };
    await saveUsers([...users, u]);
    onDone(u);
  }

  return (
    <>
      <div className="auth-head"><Logo size={68} /></div>
      <div className="card glass">
        <span className="eyebrow">{t("su_eyebrow")}</span>
        <h1 className="h1">{t("su_title")}</h1>
        <p className="muted">{t("su_sub")}</p>
        <div className="role-seg">
          <button className={"seg" + (role === "student" ? " on" : "")} onClick={() => setRole("student")}>🎓 {t("role_student")}</button>
          <button className={"seg" + (role === "teacher" ? " on" : "")} onClick={() => setRole("teacher")}>🧑‍🏫 {t("role_teacher")}</button>
        </div>
        <Field label={t("fullName")}><input className="input" value={name} onChange={(e) => { setName(e.target.value); setErr(""); }} placeholder="e.g. Aland Karim" /></Field>
        <Field label={t("lbl_dept")}>
          <select className="input" value={dept} onChange={(e) => setDept(e.target.value)}>{DEPARTMENTS.map((d) => <option key={d} value={d}>{d}</option>)}</select>
        </Field>
        {role === "student" && (
          <Field label={t("lbl_year")}>
            <select className="input" value={year} onChange={(e) => setYear(e.target.value)}><option value="1">{t("year1")}</option><option value="2">{t("year2")}</option></select>
          </Field>
        )}
        <Field label={t("emailOpt")}><input className="input" value={email} onChange={(e) => { setEmail(e.target.value); setErr(""); }} placeholder="you@sava.edu" /></Field>
        <Field label={t("choosePassword")}><input className="input" type="password" value={pw} onChange={(e) => { setPw(e.target.value); setErr(""); }} placeholder="••••••••" /></Field>
        {err && <div className="err">{err}</div>}
        <button className="btn-primary" onClick={create}>{t("su_create")}</button>
        <button className="link-back" onClick={onBack}>{t("back")}</button>
      </div>
    </>
  );
}

/* ================= PORTAL ================= */
function Portal({ current, users, saveUsers, academics, saveAcademics, finance, saveFinance, attendance, saveAttendance, announcements, saveAnnouncements, reads, saveReads, timetable, saveTimetable, assignments, saveAssignments, done, saveDone, chat, saveChat, chatReads, saveChatReads, lang, setLang, theme, setTheme, onSignOut }) {
  const role = current.role;
  const isAdmin = role === "admin";
  const newCount = users.filter((u) => u.isNew).length;
  const tabs = isAdmin
    ? [["dashboard", t("tab_dash")], ["people", t("tab_people")], ["subjects", t("tab_subjects")], ["payments", t("tab_payments")], ["news", t("tab_news")], ["timetable", t("tab_timetable")], ["chat", t("tab_chat")], ["profile", t("tab_profile")]]
    : [["home", t("tab_home")], ["timetable", t("tab_timetable")], ["assignments", t("tab_assign")], ["chat", t("tab_chat")], ["grades", t("tab_grades")], ["profile", t("tab_profile")]];
  const myCReads = (chatReads || {})[current.id] || {};
  const chatUnread = (chat.convos || []).filter((c) => c.members.includes(current.id)).reduce((sum, c) => {
    const ms = (chat.messages || {})[c.id] || [];
    const seen = myCReads[c.id] || 0;
    return sum + ms.filter((m) => m.at > seen && m.senderId !== current.id).length;
  }, 0);
  const [view, setView] = useState(tabs[0][0]);
  const [idCardUser, setIdCardUser] = useState(null);
  const [showNotif, setShowNotif] = useState(false);
  const myAnns = isAdmin ? [] : visibleAnns(announcements, current);
  const unread = myAnns.filter((a) => a.createdAt > (reads[current.id] || 0)).length;
  function openNotif() {
    setShowNotif(true);
    if (unread > 0) saveReads({ ...reads, [current.id]: Date.now() });
  }

  return (
    <div className="portal-screen">
      <header className="topbar">
        <div className="topbar-left"><Logo size={38} /><div className="topbar-title"><strong>SAVA</strong><span>Technical Institute</span></div></div>
        <div className="topbar-right">
          {!isAdmin && (
            <button className="bell" onClick={openNotif} title="Notifications">
              🔔{unread > 0 && <span className="bell-dot">{unread > 9 ? "9+" : unread}</span>}
            </button>
          )}
          <ThemeToggle theme={theme} setTheme={setTheme} />
          <LangSwitch lang={lang} setLang={setLang} compact />
          <span className="userchip"><Avatar user={current} size={26} />{current.name}</span>
          <button className="btn-ghost" onClick={onSignOut}>{t("signOut")}</button>
        </div>
      </header>

      <nav className="subnav">
        {tabs.map(([k, lbl]) => {
          let badge = 0;
          if (isAdmin && k === "people") badge = newCount;
          if (k === "chat") badge = chatUnread;
          return <button key={k} className={"tab" + (view === k ? " tab-on" : "")} onClick={() => setView(k)}>{lbl}{badge > 0 ? <span className="tab-badge">{badge > 99 ? "99+" : badge}</span> : null}</button>;
        })}
      </nav>

      <main className="portal">
        {view === "dashboard" && isAdmin && <AdminDashboard users={users} academics={academics} finance={finance} attendance={attendance} announcements={announcements} assignments={assignments} timetable={timetable} />}
        {view === "profile" && <SelfProfile me={current} saveUsers={saveUsers} users={users} onShowCard={setIdCardUser} />}
        {view === "people" && isAdmin && <AdminPeople users={users} saveUsers={saveUsers} onShowCard={setIdCardUser} />}
        {view === "subjects" && isAdmin && <SubjectsArea me={current} users={users} academics={academics} saveAcademics={saveAcademics} attendance={attendance} saveAttendance={saveAttendance} canManage={true} />}
        {view === "payments" && isAdmin && <AdminFinance users={users} finance={finance} saveFinance={saveFinance} />}
        {view === "news" && isAdmin && <AdminAnnouncements current={current} announcements={announcements} saveAnnouncements={saveAnnouncements} />}
        {view === "timetable" && isAdmin && <AdminTimetable users={users} timetable={timetable} saveTimetable={saveTimetable} />}
        {view === "timetable" && !isAdmin && <TimetableView me={current} users={users} timetable={timetable} />}
        {view === "chat" && <ChatArea me={current} users={users} chat={chat} saveChat={saveChat} chatReads={chatReads} saveChatReads={saveChatReads} />}
        {view === "assignments" && role === "teacher" && <AssignmentsTeacher me={current} assignments={assignments} saveAssignments={saveAssignments} />}
        {view === "assignments" && role === "student" && <AssignmentsStudent me={current} assignments={assignments} done={done} saveDone={saveDone} />}
        {view === "grades" && role === "teacher" && <SubjectsArea me={current} users={users} academics={academics} saveAcademics={saveAcademics} attendance={attendance} saveAttendance={saveAttendance} canManage={false} />}
        {view === "grades" && role === "student" && <StudentGrades me={current} academics={academics} attendance={attendance} />}
        {view === "home" && !isAdmin && (
          <section>
            <DeptBanner department={current.department} year={role === "student" ? current.year : ""} />
            <AnnouncementsCard user={current} announcements={announcements} />
            <TodayCard me={current} users={users} timetable={timetable} />
            {role === "student" && <HomeworkCard me={current} assignments={assignments} done={done} />}
            <IdCard user={current} big />
            <button className="id-cta" onClick={() => setIdCardUser(current)}>{t("idcardBtn")}</button>
            <FinanceCard user={current} finance={finance} />
            <div className="card soon" style={{ marginTop: 18 }}>
              <h2 className="h2" style={{ marginTop: 0 }}>{t("welcomeTitle")}</h2>
              <p className="muted">{role === "teacher" ? t("teacherHint") : t("studentHint")}</p>
            </div>
          </section>
        )}
      </main>
      {idCardUser && <IdCardOverlay user={idCardUser} onClose={() => setIdCardUser(null)} />}
      {showNotif && <NotificationsOverlay user={current} announcements={announcements} onClose={() => setShowNotif(false)} />}
    </div>
  );
}

function SelfProfile({ me, saveUsers, users, onShowCard }) {
  const [photo, setPhoto] = useState(me.photo);
  const [phone, setPhone] = useState(me.phone || "");
  const [blood, setBlood] = useState(me.blood || "");
  const [pw, setPw] = useState("");
  const [saved, setSaved] = useState(false);
  const color = ROLE_META[me.role].color;

  async function save() {
    const updated = users.map((u) => u.id === me.id ? { ...u, photo, phone: phone.trim(), blood, ...(pw ? { pw: hashPw(pw) } : {}) } : u);
    await saveUsers(updated);
    setPw(""); setSaved(true); setTimeout(() => setSaved(false), 2200);
  }

  return (
    <section>
      <p className="muted" style={{ marginBottom: 10, fontWeight: 600 }}>{t("p_yourcard")}</p>
      <IdCard user={{ ...me, photo, phone, blood }} big />
      <button className="id-cta" onClick={() => onShowCard({ ...me, photo, phone, blood })}>{t("idcardBtn")}</button>
      <div className="card" style={{ marginTop: 18 }}>
        <span className="eyebrow">{t("p_editprofile")}</span>
        <h2 className="h2" style={{ marginBottom: 14 }}>{t("p_yourdetails")}</h2>
        <PhotoPicker value={photo} onChange={setPhoto} color={color} />
        <div className="grid2" style={{ marginTop: 6 }}>
          <Field label={t("lbl_phone")}><input className="input" value={phone} onChange={(e) => setPhone(e.target.value)} placeholder="07xx xxx xxxx" /></Field>
          <Field label={t("lbl_blood")}>
            <select className="input" value={blood} onChange={(e) => setBlood(e.target.value)}>
              <option value="">—</option>{BLOOD.map((b) => <option key={b} value={b}>{b}</option>)}
            </select>
          </Field>
        </div>
        <Field label={t("p_changepw")}><input className="input" type="password" value={pw} onChange={(e) => setPw(e.target.value)} placeholder="Leave empty to keep current" /></Field>
        <div className="readonly-note">{me.role !== "admin" ? t("p_readonly_full") : t("p_readonly_admin")}</div>
        <button className="btn-primary" onClick={save}>{saved ? t("saved") : t("save")}</button>
      </div>
    </section>
  );
}

function AdminPeople({ users, saveUsers, onShowCard }) {
  const [adding, setAdding] = useState(false);
  const [editing, setEditing] = useState(null);
  const [filter, setFilter] = useState("all");
  const [q, setQ] = useState("");

  const counts = {
    all: users.length,
    admin: users.filter((u) => u.role === "admin").length,
    teacher: users.filter((u) => u.role === "teacher").length,
    student: users.filter((u) => u.role === "student").length,
  };
  const shown = (filter === "all" ? users : users.filter((u) => u.role === filter)).filter((u) => matchName(u, q)).slice().sort((a, b) => a.createdAt - b.createdAt);

  async function addPerson(data, pw) {
    const u = { ...data, id: nextId(users, data.role), pw: hashPw(pw), createdAt: Date.now() };
    if (u.role !== "student") u.year = "";
    await saveUsers([...users, u]);
    setAdding(false);
  }
  async function saveEdit(data, pw) {
    const updated = users.map((u) => u.id === editing.id
      ? { ...u, ...data, ...(pw ? { pw: hashPw(pw) } : {}), year: data.role === "student" ? data.year : "" }
      : u);
    await saveUsers(updated);
    setEditing(null);
  }
  async function remove(id) { await saveUsers(users.filter((u) => u.id !== id)); }
  async function markSeen() { await saveUsers(users.map((u) => u.isNew ? { ...u, isNew: false } : u)); }
  const newOnes = users.filter((u) => u.isNew);

  return (
    <section>
      <div className="section-head">
        <div><span className="eyebrow">Admin</span><h2 className="h2">{t("peopleTitle")}</h2></div>
        <button className="btn-primary small" onClick={() => setAdding(true)}>{t("addAccount")}</button>
      </div>

      {newOnes.length > 0 && (
        <div className="newbanner">
          <span>🆕 {newOnes.length} {t("new_signups")}</span>
          <button className="btn-ghost small" onClick={markSeen}>{t("mark_seen")}</button>
        </div>
      )}

      <div className="filters">
        {["all", "student", "teacher", "admin"].map((f) => (
          <button key={f} className={"chip" + (filter === f ? " chip-on" : "")} onClick={() => setFilter(f)}>
            {f === "all" ? t("everyone") : roleLabel(f)} <b>{counts[f]}</b>
          </button>
        ))}
      </div>

      <SearchBox value={q} onChange={setQ} placeholder="Search students or teachers…" />

      {shown.length === 0 ? (
        <div className="empty">{q ? "No one matches “" + q + "”." : "No accounts here yet. Use “+ Add account” to create one."}</div>
      ) : (
        <div className="cards">
          {shown.map((u) => (
            <div key={u.id} className="card-row">
              <IdCard user={u} />
              <div className="row-actions">
                {u.isNew && <span className="newtag">{t("new_badge")}</span>}
                <button className="btn-ghost small" onClick={() => onShowCard(u)}>ID card</button>
                <button className="btn-ghost small" onClick={() => setEditing(u)}>Edit</button>
                {u.role !== "admin" && <button className="btn-remove" onClick={() => remove(u.id)}>Remove</button>}
              </div>
            </div>
          ))}
        </div>
      )}

      {adding && <PersonModal title="Add account" mode="add" onSave={addPerson} onCancel={() => setAdding(false)} previewId={(role) => nextId(users, role)} />}
      {editing && <PersonModal title="Edit account" mode="edit" person={editing} onSave={saveEdit} onCancel={() => setEditing(null)} />}
    </section>
  );
}

