function Attendance({ subject, users, attendance, saveAttendance }) {
  const students = users.filter((u) => u.role === "student" && u.department === subject.department && u.year === subject.year).sort((a, b) => a.createdAt - b.createdAt);
  const today = new Date().toISOString().slice(0, 10);
  const [date, setDate] = useState(today);
  const [marks, setMarks] = useState(() => { const subj = attendance[subject.id] || {}; return { ...(subj[today] || {}) }; });
  const [saved, setSaved] = useState(false);
  const [q, setQ] = useState("");
  const visible = students.filter((s) => matchName(s, q));

  useEffect(() => {
    const subj = attendance[subject.id] || {};
    setMarks({ ...(subj[date] || {}) });
    setSaved(false);
  }, [date]);

  function setStatus(sid, status) { setMarks((m) => ({ ...m, [sid]: status })); setSaved(false); }
  function markAll(status) { const m = {}; students.forEach((s) => { m[s.id] = status; }); setMarks(m); setSaved(false); }
  async function save() {
    const subj = { ...(attendance[subject.id] || {}) };
    subj[date] = marks;
    await saveAttendance({ ...attendance, [subject.id]: subj });
    setSaved(true); setTimeout(() => setSaved(false), 1800);
  }

  return (
    <>
      <div className="att-controls">
        <input className="input att-date" type="date" value={date} onChange={(e) => setDate(e.target.value)} />
        <button className="btn-ghost small" onClick={() => markAll("present")}>{t("allPresent")}</button>
      </div>
      {students.length === 0 ? (
        <div className="empty">No students in {subject.department}, Year {subject.year} yet. Add them in People.</div>
      ) : (
        <>
          <SearchBox value={q} onChange={setQ} placeholder="Search a student…" />
          <div className="grade-list">
            {visible.map((s) => {
              const cur = marks[s.id];
              const c = attCounts(attendance, subject.id, s.id);
              const rate = c.total === 0 ? null : Math.round(((c.p + c.l) / c.total) * 100);
              return (
                <div key={s.id} className="att-row card">
                  <div className="grade-student"><Avatar user={s} size={36} /><div><div className="grade-sname">{s.name}</div><div className="grade-sid">{rate == null ? "No sessions yet" : "Attendance " + rate + "% · " + c.p + "P " + c.l + "L " + c.a + "A"}</div></div></div>
                  <div className="att-btns">
                    {[["present", "P", "#34D399"], ["late", "L", "#F59E0B"], ["absent", "A", "#F87171"]].map(([k, lbl, col]) => (
                      <button key={k} className="att-b" style={cur === k ? { background: col, borderColor: col, color: "#0B0E1A" } : { color: col, borderColor: col + "55" }} onClick={() => setStatus(s.id, k)}>{lbl}</button>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
          <button className="btn-primary" onClick={save}>{saved ? "Saved ✓" : "Save attendance"}</button>
        </>
      )}
    </>
  );
}

/* ================= FINANCE ================= */
const CURRENCY = "$"; // change to "IQD", "€", etc.
function money(n) { return CURRENCY + (Number(n) || 0).toLocaleString(); }
function finOf(finance, id) { const f = finance[id]; return { total: f ? Number(f.total) || 0 : 0, entries: f && f.entries ? f.entries : [] }; }
function finPaid(entries) { return entries.reduce((a, e) => a + (Number(e.amount) || 0), 0); }
function finStatus(total, paid) {
  if (total > 0 && paid >= total) return { label: t("st_paid"), color: "#34D399" };
  if (paid > 0) return { label: t("st_partial"), color: "#F59E0B" };
  return { label: t("st_unpaid"), color: "#F87171" };
}
function fmtDate(ts) { try { return new Date(ts).toLocaleDateString(); } catch (_) { return ""; } }

function FinanceCard({ user, finance }) {
  const isStudent = user.role === "student";
  const { total, entries } = finOf(finance, user.id);
  const paid = finPaid(entries);
  const remaining = total - paid;
  const st = finStatus(total, paid);
  const labels = isStudent ? { total: "Tuition", paid: "Paid", rem: "Balance" } : { total: "Salary", paid: "Paid", rem: "Remaining" };
  if (total === 0 && entries.length === 0) {
    return (
      <div className="card fin-card" style={{ marginTop: 18 }}>
        <span className="eyebrow">{isStudent ? "Payments" : "Salary"}</span>
        <p className="muted" style={{ marginTop: 8 }}>{isStudent ? "No tuition set yet. Your admin will add it." : "No salary set yet. Your admin will add it."}</p>
      </div>
    );
  }
  return (
    <div className="card fin-card" style={{ marginTop: 18 }}>
      <div className="fin-head">
        <span className="eyebrow">{isStudent ? "Payments" : "Salary"}</span>
        <span className="status-pill" style={{ color: st.color, borderColor: st.color + "55", background: st.color + "1a" }}>{st.label}</span>
      </div>
      <div className="fin-figs">
        <div><span>{labels.total}</span><b>{money(total)}</b></div>
        <div><span>{labels.paid}</span><b style={{ color: "#34D399" }}>{money(paid)}</b></div>
        <div><span>{labels.rem}</span><b style={{ color: remaining > 0 ? "#F59E0B" : "#9AA5C4" }}>{money(Math.max(0, remaining))}</b></div>
      </div>
      {entries.length > 0 && (
        <div className="fin-history">
          <div className="fin-history-title">History</div>
          {entries.slice().reverse().map((e) => (
            <div key={e.id} className="fin-row">
              <span className="fin-amt">{money(e.amount)}</span>
              <span className="fin-date">{fmtDate(e.date)}{e.note ? " · " + e.note : ""}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

