function AssignmentsStudent({ me, assignments, done, saveDone }) {
  const [filter, setFilter] = useState("all");
  if (!me.department) return <section><div className="empty">{t("as_deptnotset")}</div></section>;
  const myDone = (done || {})[me.id] || {};
  const list = (assignments || []).filter((a) => a.dept === me.department && a.year === me.year).slice().sort((a, b) => (a.due || "9999").localeCompare(b.due || "9999"));
  const counts = { all: list.length, todo: list.filter((a) => !myDone[a.id]).length, done: list.filter((a) => !!myDone[a.id]).length };
  const shown = list.filter((a) => filter === "all" ? true : filter === "done" ? !!myDone[a.id] : !myDone[a.id]);

  async function toggle(id) {
    const cur = { ...((done || {})[me.id] || {}) };
    if (cur[id]) delete cur[id]; else cur[id] = true;
    await saveDone({ ...(done || {}), [me.id]: cur });
  }

  return (
    <section>
      <div className="section-head"><div><span className="eyebrow">{t("as_mywork")}</span><h2 className="h2">{t("assign_title")}</h2></div></div>
      <div className="filters">
        {[["all", t("as_all")], ["todo", t("as_todo")], ["done", t("as_done")]].map(([k, lbl]) => (
          <button key={k} className={"chip" + (filter === k ? " chip-on" : "")} onClick={() => setFilter(k)}>{lbl} <b>{counts[k]}</b></button>
        ))}
      </div>
      {shown.length === 0 ? (
        <div className="empty">{filter === "done" ? t("as_emptydone") : filter === "todo" ? t("as_emptytodo") : t("as_emptyall")}</div>
      ) : (
        <div className="asgs">
          {shown.map((a) => <AssignmentItem key={a.id} a={a} done={!!myDone[a.id]} onToggle={() => toggle(a.id)} />)}
        </div>
      )}
    </section>
  );
}

