function ChatThread({ conv, title, other, messages, me, users, onSend, onBack }) {
  const [draft, setDraft] = useState("");
  const endRef = useRef(null);
  useEffect(() => { if (endRef.current) endRef.current.scrollIntoView({ block: "end" }); }, [messages.length]);
  const isGroup = conv.type === "group";
  function userById(id) { return users.find((u) => u.id === id); }
  function submit() { if (!draft.trim()) return; onSend(draft); setDraft(""); }
  return (
    <section className="chat-section">
      <div className="chat-head">
        <button className="chat-back" onClick={onBack}>←</button>
        {other ? <Avatar user={other} size={34} /> : <div className="group-av sm">👥</div>}
        <div className="chat-title">
          <div className="chat-name">{title}</div>
          {isGroup ? <div className="chat-sub">{conv.members.length} {t("chat_members")}</div> : (other ? <div className="chat-sub">{roleLabel(other.role)}</div> : null)}
        </div>
      </div>
      <div className="msgs">
        {messages.length === 0 ? <div className="empty">{t("chat_empty")}</div> : messages.map((m, i) => {
          const mine = m.senderId === me.id;
          const sender = userById(m.senderId);
          const prev = messages[i - 1];
          const showName = isGroup && !mine && (!prev || prev.senderId !== m.senderId);
          return (
            <div key={m.id} className={"msg" + (mine ? " mine" : "")}>
              {showName ? <div className="msg-sender">{sender ? sender.name : "?"}</div> : null}
              <div className="bubble">{m.text}</div>
              <div className="msg-time">{new Date(m.at).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}</div>
            </div>
          );
        })}
        <div ref={endRef} />
      </div>
      <div className="chat-input">
        <input className="input" value={draft} onChange={(e) => setDraft(e.target.value)} placeholder={t("chat_typemsg")} onKeyDown={(e) => e.key === "Enter" && submit()} />
        <button className="chat-send" onClick={submit}>➤</button>
      </div>
    </section>
  );
}

function ChatArea({ me, users, chat, saveChat, chatReads, saveChatReads }) {
  const [openId, setOpenId] = useState(null);
  const [composing, setComposing] = useState(null);
  const [q, setQ] = useState("");
  const [gname, setGname] = useState("");
  const [gsel, setGsel] = useState([]);

  const convos = chat.convos || [];
  const messages = chat.messages || {};
  const myConvos = convos.filter((c) => c.members.includes(me.id)).slice().sort((a, b) => (b.lastAt || b.createdAt) - (a.lastAt || a.createdAt));
  const myReads = (chatReads || {})[me.id] || {};
  const others = users.filter((u) => u.id !== me.id);
  function userById(id) { return users.find((u) => u.id === id); }
  function convName(c) { if (c.type === "group") return c.name || "Group"; const o = userById(c.members.find((m) => m !== me.id)); return o ? o.name : "Unknown"; }
  function convOther(c) { return c.type === "dm" ? userById(c.members.find((m) => m !== me.id)) : null; }
  function unreadOf(c) { const ms = messages[c.id] || []; const seen = myReads[c.id] || 0; return ms.filter((m) => m.at > seen && m.senderId !== me.id).length; }
  function lastMsg(c) { const ms = messages[c.id] || []; return ms.length ? ms[ms.length - 1] : null; }

  async function open(id) {
    setOpenId(id);
    const r = { ...(chatReads || {}) };
    r[me.id] = { ...(r[me.id] || {}), [id]: Date.now() };
    await saveChatReads(r);
  }
  async function send(convId, text) {
    if (!text.trim()) return;
    const at = Date.now();
    const msg = { id: "M" + at + Math.random().toString(36).slice(2, 6), senderId: me.id, text: text.trim(), at };
    await saveChat({ convos: convos.map((c) => c.id === convId ? { ...c, lastAt: at } : c), messages: { ...messages, [convId]: [...(messages[convId] || []), msg] } });
    const r = { ...(chatReads || {}) };
    r[me.id] = { ...(r[me.id] || {}), [convId]: at };
    await saveChatReads(r);
  }
  async function startDM(otherId) {
    let dm = convos.find((c) => c.type === "dm" && c.members.length === 2 && c.members.includes(me.id) && c.members.includes(otherId));
    if (!dm) {
      dm = { id: "C" + Date.now() + Math.random().toString(36).slice(2, 6), type: "dm", members: [me.id, otherId], name: "", createdBy: me.id, createdAt: Date.now(), lastAt: Date.now() };
      await saveChat({ convos: [...convos, dm], messages });
    }
    setComposing(null); setQ(""); setOpenId(dm.id);
  }
  async function createGroup() {
    const members = Array.from(new Set([me.id, ...gsel]));
    if (members.length < 2) return;
    const g = { id: "C" + Date.now() + Math.random().toString(36).slice(2, 6), type: "group", members, name: gname.trim() || "Group", createdBy: me.id, createdAt: Date.now(), lastAt: Date.now() };
    await saveChat({ convos: [...convos, g], messages });
    setComposing(null); setGname(""); setGsel([]); setOpenId(g.id);
  }

  const openConv = myConvos.find((c) => c.id === openId);
  if (openConv) {
    return <ChatThread conv={openConv} title={convName(openConv)} other={convOther(openConv)} messages={messages[openConv.id] || []} me={me} users={users} onSend={(txt) => send(openConv.id, txt)} onBack={() => setOpenId(null)} />;
  }

  if (composing === "dm") {
    const list = others.filter((u) => matchName(u, q));
    return (
      <section>
        <div className="chat-head"><button className="chat-back" onClick={() => { setComposing(null); setQ(""); }}>←</button><h2 className="h2" style={{ margin: 0 }}>{t("chat_dm")}</h2></div>
        <SearchBox value={q} onChange={setQ} placeholder={t("chat_pickperson")} />
        <div className="convos" style={{ marginTop: 6 }}>
          {list.map((u) => (
            <button key={u.id} className="person-pick" onClick={() => startDM(u.id)}>
              <Avatar user={u} size={40} />
              <div className="pick-main"><div className="pick-name">{u.name}</div><div className="pick-sub">{roleLabel(u.role)}{u.department ? " · " + u.department : ""}</div></div>
            </button>
          ))}
          {list.length === 0 && <div className="empty">—</div>}
        </div>
      </section>
    );
  }
  if (composing === "group") {
    return (
      <section>
        <div className="chat-head"><button className="chat-back" onClick={() => { setComposing(null); setGname(""); setGsel([]); }}>←</button><h2 className="h2" style={{ margin: 0 }}>{t("chat_group")}</h2></div>
        <Field label={t("chat_groupname")}><input className="input" value={gname} onChange={(e) => setGname(e.target.value)} placeholder="e.g. Year 1 Nursing" /></Field>
        <p className="muted" style={{ margin: "6px 0 8px", fontWeight: 600 }}>{t("chat_members")} ({gsel.length})</p>
        <div className="convos">
          {others.map((u) => {
            const on = gsel.includes(u.id);
            return (
              <button key={u.id} className={"person-pick" + (on ? " picked" : "")} onClick={() => setGsel(on ? gsel.filter((x) => x !== u.id) : [...gsel, u.id])}>
                <Avatar user={u} size={40} />
                <div className="pick-main"><div className="pick-name">{u.name}</div><div className="pick-sub">{roleLabel(u.role)}{u.department ? " · " + u.department : ""}</div></div>
                <span className="pick-check">{on ? "✓" : ""}</span>
              </button>
            );
          })}
        </div>
        <button className="btn-primary" style={{ marginTop: 14 }} onClick={createGroup} disabled={gsel.length === 0}>{t("chat_create")}</button>
      </section>
    );
  }
  if (composing === "menu") {
    return (
      <section>
        <div className="chat-head"><button className="chat-back" onClick={() => setComposing(null)}>←</button><h2 className="h2" style={{ margin: 0 }}>{t("chat_new")}</h2></div>
        <button className="id-cta" onClick={() => setComposing("dm")}>💬 {t("chat_dm")}</button>
        <button className="id-cta" onClick={() => setComposing("group")}>👥 {t("chat_group")}</button>
      </section>
    );
  }

  return (
    <section>
      <div className="section-head"><div><span className="eyebrow">SAVA</span><h2 className="h2">{t("tab_chat")}</h2></div><button className="btn-primary small" onClick={() => setComposing("menu")}>+ {t("chat_new")}</button></div>
      {myConvos.length === 0 ? (
        <div className="empty">{t("chat_nochats")}</div>
      ) : (
        <div className="convos">
          {myConvos.map((c) => {
            const u = unreadOf(c);
            const lm = lastMsg(c);
            const other = convOther(c);
            return (
              <button key={c.id} className="convo" onClick={() => open(c.id)}>
                {other ? <Avatar user={other} size={46} /> : <div className="group-av">👥</div>}
                <div className="convo-main">
                  <div className="convo-top"><div className="convo-name">{convName(c)}</div>{lm ? <span className="convo-time">{timeAgo(lm.at)}</span> : null}</div>
                  <div className="convo-prev">{lm ? (lm.senderId === me.id ? t("chat_you") + ": " : "") + lm.text : "—"}</div>
                </div>
                {u > 0 ? <span className="convo-badge">{u}</span> : null}
              </button>
            );
          })}
        </div>
      )}
    </section>
  );
}

function AdminDashboard({ users, academics, finance, attendance, announcements, assignments, timetable }) {
  const students = users.filter((u) => u.role === "student");
  const teachers = users.filter((u) => u.role === "teacher");
  const subjects = academics.subjects || [];

  let tExpected = 0, tCollected = 0;
  students.forEach((s) => { const f = finOf(finance, s.id); tExpected += f.total; tCollected += finPaid(f.entries); });
  const tOutstanding = Math.max(0, tExpected - tCollected);
  const tPct = tExpected > 0 ? Math.round((tCollected / tExpected) * 100) : 0;

  let salTotal = 0, salPaid = 0;
  teachers.forEach((tch) => { const f = finOf(finance, tch.id); salTotal += f.total; salPaid += finPaid(f.entries); });

  let present = 0, late = 0, absent = 0, total = 0, sessions = 0;
  Object.values(attendance || {}).forEach((byDate) => {
    Object.values(byDate || {}).forEach((byStudent) => {
      sessions++;
      Object.values(byStudent || {}).forEach((st) => { total++; if (st === "present") present++; else if (st === "late") late++; else if (st === "absent") absent++; });
    });
  });
  const attPct = total ? Math.round(((present + late) / total) * 100) : null;
  const classesWithTT = Object.keys(timetable || {}).filter((k) => (timetable[k] || []).length > 0).length;

  const byDept = DEPARTMENTS.map((d) => ({ d, n: students.filter((s) => s.department === d).length })).filter((x) => x.n > 0).sort((a, b) => b.n - a.n);
  const maxDept = Math.max(1, ...byDept.map((x) => x.n));

  const tiles = [
    { ic: "🎓", n: students.length, l: t("d_students") },
    { ic: "🧑‍🏫", n: teachers.length, l: t("d_teachers") },
    { ic: "📚", n: subjects.length, l: t("d_subjects") },
    { ic: "📅", n: classesWithTT, l: t("d_classes") },
    { ic: "📢", n: (announcements || []).length, l: t("c_announce") },
    { ic: "📝", n: (assignments || []).length, l: t("assign_title") },
    { ic: "🆕", n: users.filter((u) => u.isNew).length, l: t("new_signups") },
  ];

  return (
    <section>
      <div className="section-head"><div><span className="eyebrow">{t("ey_admin")}</span><h2 className="h2">{t("tab_dash")}</h2></div></div>

      <div className="dash-grid">
        {tiles.map((tl) => (
          <div className="tile" key={tl.l}>
            <span className="tile-ic">{tl.ic}</span>
            <div className="tile-n">{tl.n}</div>
            <div className="tile-l">{tl.l}</div>
          </div>
        ))}
      </div>

      <div className="card" style={{ marginTop: 16 }}>
        <span className="eyebrow">{t("d_tuition")}</span>
        <div className="fin-figs" style={{ marginTop: 10 }}>
          <div><span>{t("d_expected")}</span><b>{money(tExpected)}</b></div>
          <div><span>{t("d_collected")}</span><b style={{ color: "#34D399" }}>{money(tCollected)}</b></div>
          <div><span>{t("d_outstanding")}</span><b style={{ color: tOutstanding > 0 ? "#F59E0B" : "#9AA5C4" }}>{money(tOutstanding)}</b></div>
        </div>
        <div className="bar" style={{ marginTop: 12 }}><i style={{ width: tPct + "%", background: "#34D399" }} /></div>
        <div className="muted" style={{ fontSize: 12, marginTop: 6 }}>{tPct}% {t("d_collected_of")}</div>
      </div>

      <div className="card" style={{ marginTop: 14 }}>
        <span className="eyebrow">{t("d_salary")}</span>
        <div className="fin-figs" style={{ marginTop: 10 }}>
          <div><span>{t("d_total")}</span><b>{money(salTotal)}</b></div>
          <div><span>{t("d_paid")}</span><b style={{ color: "#34D399" }}>{money(salPaid)}</b></div>
          <div><span>{t("d_remaining")}</span><b style={{ color: (salTotal - salPaid) > 0 ? "#F59E0B" : "#9AA5C4" }}>{money(Math.max(0, salTotal - salPaid))}</b></div>
        </div>
      </div>

      <div className="card" style={{ marginTop: 14 }}>
        <span className="eyebrow">{t("d_attendance")}</span>
        {attPct === null ? (
          <p className="muted" style={{ marginTop: 8 }}>{t("d_noatt")}</p>
        ) : (
          <>
            <div style={{ display: "flex", alignItems: "baseline", gap: 8, marginTop: 8 }}>
              <div style={{ fontSize: 30, fontWeight: 800 }}>{attPct}%</div>
              <div className="muted" style={{ fontSize: 13 }}>{t("d_overall")}</div>
            </div>
            <div className="bar" style={{ marginTop: 10 }}><i style={{ width: attPct + "%", background: "#10B981" }} /></div>
            <div className="kpi" style={{ marginTop: 10 }}>
              <span>✅ {t("att_present")} <b>{present}</b></span>
              <span>🕒 {t("att_late")} <b>{late}</b></span>
              <span>❌ {t("att_absent")} <b>{absent}</b></span>
              <span>· {sessions} {t("d_sessions")}</span>
            </div>
          </>
        )}
      </div>

      <div className="card" style={{ marginTop: 14 }}>
        <span className="eyebrow">{t("d_bydept")}</span>
        {byDept.length === 0 ? (
          <p className="muted" style={{ marginTop: 8 }}>{t("d_nostudents")}</p>
        ) : (
          <div style={{ marginTop: 10 }}>
            {byDept.map((x) => (
              <div className="deptbar-row" key={x.d}>
                <div className="deptbar-name">{x.d}</div>
                <div className="deptbar-track"><i style={{ width: (x.n / maxDept * 100) + "%", background: deptColor(x.d) }} /></div>
                <div className="deptbar-n">{x.n}</div>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

function AdminFinance({ users, finance, saveFinance }) {
  const [filter, setFilter] = useState("student");
  const [editing, setEditing] = useState(null);
  const list = users.filter((u) => u.role === filter).sort((a, b) => a.createdAt - b.createdAt);
  return (
    <section>
      <div className="section-head"><div><span className="eyebrow">Admin</span><h2 className="h2">{t("paymentsTitle")}</h2></div></div>
      <div className="filters">
        <button className={"chip" + (filter === "student" ? " chip-on" : "")} onClick={() => setFilter("student")}>Students <b>{users.filter((u) => u.role === "student").length}</b></button>
        <button className={"chip" + (filter === "teacher" ? " chip-on" : "")} onClick={() => setFilter("teacher")}>Teachers <b>{users.filter((u) => u.role === "teacher").length}</b></button>
      </div>
      {list.length === 0 ? (
        <div className="empty">No {filter}s yet. Add them in People.</div>
      ) : (
        <div className="cards">
          {list.map((u) => {
            const { total, entries } = finOf(finance, u.id);
            const paid = finPaid(entries);
            const st = finStatus(total, paid);
            return (
              <div key={u.id} className="card-row">
                <IdCard user={u} />
                <div className="fin-mini">
                  <span className="status-pill" style={{ color: st.color, borderColor: st.color + "55", background: st.color + "1a" }}>{st.label}</span>
                  <span className="fin-bal">{money(Math.max(0, total - paid))} left</span>
                  <button className="btn-ghost small" onClick={() => setEditing(u)}>Manage</button>
                </div>
              </div>
            );
          })}
        </div>
      )}
      {editing && <FinanceEditor user={editing} finance={finance} saveFinance={saveFinance} onClose={() => setEditing(null)} />}
    </section>
  );
}

function FinanceEditor({ user, finance, saveFinance, onClose }) {
  const isStudent = user.role === "student";
  const init = finOf(finance, user.id);
  const [total, setTotal] = useState(init.total ? String(init.total) : "");
  const [entries, setEntries] = useState(init.entries);
  const [amt, setAmt] = useState("");
  const [note, setNote] = useState("");
  const [saved, setSaved] = useState(false);
  const totalNum = Number(total) || 0;
  const paid = finPaid(entries);
  const remaining = totalNum - paid;
  const st = finStatus(totalNum, paid);

  function addPayment() {
    const a = Math.round(Number(amt));
    if (!a || a <= 0) return;
    setEntries((es) => [...es, { id: Date.now(), amount: a, date: Date.now(), note: note.trim() }]);
    setAmt(""); setNote(""); setSaved(false);
  }
  function removeEntry(id) { setEntries((es) => es.filter((e) => e.id !== id)); setSaved(false); }
  async function save() {
    await saveFinance({ ...finance, [user.id]: { total: totalNum, entries } });
    setSaved(true); setTimeout(() => setSaved(false), 1800);
  }

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal card" onClick={(e) => e.stopPropagation()}>
        <div className="modal-head"><h2 className="h2" style={{ margin: 0 }}>{user.name}</h2><button className="x" onClick={onClose}>✕</button></div>
        <div className="subject-meta" style={{ marginBottom: 14 }}>{user.id} · {isStudent ? "Student tuition" : "Teacher salary"}</div>
        <Field label={isStudent ? "Total tuition" : "Total salary"}>
          <input className="input" type="number" min="0" value={total} onChange={(e) => { setTotal(e.target.value); setSaved(false); }} placeholder={"Amount in " + CURRENCY} />
        </Field>
        <div className="fin-summary">
          <div><span>Paid</span><b style={{ color: "#34D399" }}>{money(paid)}</b></div>
          <div><span>Remaining</span><b style={{ color: remaining > 0 ? "#F59E0B" : "#9AA5C4" }}>{money(Math.max(0, remaining))}</b></div>
          <span className="status-pill" style={{ color: st.color, borderColor: st.color + "55", background: st.color + "1a" }}>{st.label}</span>
        </div>
        <div className="add-pay">
          <input className="input" type="number" min="0" value={amt} onChange={(e) => setAmt(e.target.value)} placeholder="Payment amount" />
          <input className="input" value={note} onChange={(e) => setNote(e.target.value)} placeholder="Note (optional)" />
          <button className="btn-ghost small" onClick={addPayment}>+ Add</button>
        </div>
        {entries.length > 0 && (
          <div className="fin-history">
            <div className="fin-history-title">Payment history</div>
            {entries.slice().reverse().map((e) => (
              <div key={e.id} className="fin-row">
                <span className="fin-amt">{money(e.amount)}</span>
                <span className="fin-date">{fmtDate(e.date)}{e.note ? " · " + e.note : ""}</span>
                <button className="btn-remove tiny" onClick={() => removeEntry(e.id)}>✕</button>
              </div>
            ))}
          </div>
        )}
        <div className="modal-actions">
          <button className="btn-ghost" onClick={onClose}>Close</button>
          <button className="btn-primary small" onClick={save}>{saved ? "Saved ✓" : "Save"}</button>
        </div>
      </div>
    </div>
  );
}

